# Pricing normalization
def _price(free_plan, model):
    fp = (free_plan or "").strip().lower()
    m = (model or "").strip().lower()
    if "free" in m and "freemium" not in m and "subscription" not in m and fp == "yes":
        return "free"
    if fp == "yes":
        return "freemium"
    return "paid"


