def build_extra_tools():
    out = []
    for row in RAW:
        name, company, url, cat, desc, best_for, free_plan, model = row
        slug = _slug(name)
        category = CAT_MAP.get(cat, "chat")
        out.append({
            "name": name,
            "slug": slug,
            "tagline": desc[:120],
            "description": f"{desc} By {company}.",
            "category": category,
            "category_slugs": [category],
            "pricing": _price(free_plan, model),
            "url": url,
            "logo_url": None,
            "use_cases": [best_for] if best_for else [],
            "free_alternatives": [],
            "best_prompts": [],
            "pros": [],
            "cons": [],
            "professions": [],
            "start_here_workflow": [],
            "make_money_module": [],
            "irl_use_cases": [],
            "featured": False,
            "trending": False,
            "new_launch": False,
            "updated_recently": False,
            "view_count": 0,
        })
    return out
